class VoiceState:
    def __init__(self): self.enabled=True
    def toggle(self):
        self.enabled=not self.enabled
        print("VOICE:","ON" if self.enabled else "OFF")
        if not self.enabled: stop()
        return self.enabled
    @property
    def is_on(self): return self.enabled

voice = VoiceState()
voice_lang = "hi"   # default; set from main.py
def toggle_voice(): return voice.toggle()

_alias="ainews"; _playing=False

def stop():
    global _playing; _playing=False
    try:
        if sys.platform=="win32":
            import ctypes; w=ctypes.windll.winmm
            w.mciSendStringW(f"stop {_alias}",None,0,None)
            w.mciSendStringW(f"close {_alias}",None,0,None)
        elif sys.platform=="darwin": os.system("killall afplay 2>/dev/null")
        else: os.system("killall aplay mpg123 2>/dev/null")
    except: pass

def _play_file(path, lang):
    global _playing; _playing=True
    try:
        if sys.platform=="win32":
            import ctypes; w=ctypes.windll.winmm; buf=ctypes.create_unicode_buffer(128)
            w.mciSendStringW(f"close {_alias}",None,0,None)
            w.mciSendStringW(f'open "{path}" type mpegvideo alias {_alias}',None,0,None)
            w.mciSendStringW(f"play {_alias}",None,0,None)
            while _playing and voice.is_on:
                w.mciSendStringW(f"status {_alias} mode",buf,128,None)
                if buf.value not in ("playing",""): break
                time.sleep(0.15)
            w.mciSendStringW(f"stop {_alias}",None,0,None)
            w.mciSendStringW(f"close {_alias}",None,0,None)
        elif sys.platform=="darwin": os.system(f'afplay "{path}"')
        else: os.system(f'aplay "{path}" 2>/dev/null || mpg123 "{path}" 2>/dev/null')
    finally: _playing=False

def _clean(text):
    if not text: return ""
    text=re.sub(r"<[^>]+>"," ",text)
    for e,r in [("&nbsp;"," "),("&amp;","and"),("&lt;",""),("&gt;",""),("&quot;",'"')]:
        text=text.replace(e,r)
    text=re.sub(r"&[a-z#0-9]+;"," ",text)
    text=re.sub(r"http[s]?://\S+","",text)
    text=re.sub(r"\b[\w.-]+\.(com|in|org|net|io|co)\S*","",text)
    return re.sub(r"\s{2,}"," ",text).strip()

