_SIMPLIFY_PAIRS = sorted(_HINDI_SIMPLIFY.items(), key=lambda x: len(x[0]), reverse=True)

def _translate(text, lang):
    if lang=="en" or not text: return text
    if not GoogleTranslator: return text
    try:
        res = GoogleTranslator(source="en",target=lang).translate(text[:500])
        if lang == "hi" and res:
            for k, v in _SIMPLIFY_PAIRS:
                res = res.replace(k, v)
        return res
    except: return text

def build_speech(title, summary="", lang=None):
    lang=lang or voice_lang or "hi"
    t=_translate(_clean(title),lang)
    s=_translate(_clean(summary)[:350],lang) if summary else ""
    if lang=="hi":   return f"खबर यह है — {t}। {s}" if s else f"खबर यह है — {t}"
    if lang=="ne":   return f"समाचार — {t}। {s}" if s else f"समाचार — {t}"
    return f"News: {t}. {s}" if s else f"News: {t}"

_ev=threading.Event(); _job=None; _job_lang="hi"; _jlk=threading.Lock()

def _worker():
    global _job,_job_lang
    while True:
        _ev.wait(); _ev.clear()
        with _jlk: text=_job; lang=_job_lang; _job=None
        if not text or not voice.is_on: continue
        tmp=None
        try:
            if not gTTS:
                print("VOICE: library missing")
                return
            tmp=os.path.join(tempfile.gettempdir(),f"ainews_{int(time.time()*1000)}.mp3")
            gTTS(text=text,lang=lang,slow=False).save(tmp)
            if voice.is_on and not _job: _play_file(tmp,lang)
        except Exception as e: print(f"Voice error: {e}")
        finally:
            time.sleep(0.2)
            if tmp and os.path.exists(tmp):
                try: os.remove(tmp)
                except: pass

threading.Thread(target=_worker,daemon=True).start()

def speak_article(title, summary="", lang=None):
    global _job,_job_lang
    if not voice.is_on: return
    use=lang or voice_lang or "hi"
    stop()
    with _jlk: _job=build_speech(title,summary,use); _job_lang=use
    _ev.set()